code = """import json
import pandas as pd

# Try to access the stored variables
try:
    reviews = locals().get('var_functions.query_db:6')
    if not reviews:
        reviews_key = [k for k in locals().keys() if 'query_db' in k and '6' in k][0]
        reviews = locals()[reviews_key]
    
    child_books = locals().get('var_functions.query_db:13') 
    if not child_books:
        books_key = [k for k in locals().keys() if 'query_db' in k and '13' in k][0]
        child_books = locals()[books_key]
        
    print("Retrieved variables successfully")
except Exception as e:
    print(f"Error: {e}")
    reviews = child_books = None

# Check if they're file paths
if isinstance(reviews, str) and '.json' in reviews:
    with open(reviews, 'r') as f:
        reviews = json.load(f)

if isinstance(child_books, str) and '.json' in child_books:
    with open(child_books, 'r') as f:
        child_books = json.load(f)

# Create DataFrames
reviews_df = pd.DataFrame(reviews)
books_df = pd.DataFrame(child_books)

print(f"Reviews from 2020 onwards: {len(reviews_df)}")
print(f"Children's books found: {len(books_df)}")

# Analyze the data
reviews_df['rating'] = pd.to_numeric(reviews_df['rating'])
reviews_df['id_clean'] = reviews_df['purchase_id'].str.replace('purchaseid_', '')
books_df['id_clean'] = books_df['book_id'].str.replace('bookid_', '')

# Merge
data = pd.merge(reviews_df, books_df, left_on='id_clean', right_on='id_clean', how='inner')
print(f"Matched records: {len(data)}")

# Calculate averages by book
book_stats = data.groupby(['book_id', 'title']).agg({'rating': ['mean', 'count']}).round(2)
book_stats.columns = ['avg_rating', 'review_count']
book_stats = book_stats.reset_index()

# Filter for high-rated books
high_rated = book_stats[book_stats['avg_rating'] >= 4.5]
print(f"Children's books with avg rating >= 4.5: {len(high_rated)}")

result = high_rated.sort_values(['avg_rating', 'review_count'], ascending=[False, False])

print("__RESULT__:")
print(result.to_json(orient='records'))"""

